/** Resolve a 5-digit ZIP code to state code and optional metro area */
export function resolveZip(zip: string): { state: string; metroId?: string; metro?: MetroWageData } | null {
    if (!zip || zip.length < 3) return null;
    const z3 = zip.slice(0, 3);
    const z3num = parseInt(z3, 10);
    if (isNaN(z3num)) return null;

    // Find state from ZIP3 ranges
    let state = "";
    for (const [min, max, st] of ZIP3_STATE) {
        if (z3num >= min && z3num <= max) { state = st; break; }
    }
    if (!state) return null;

    // Find metro from ZIP3 → MSA mapping
    const msaCode = ZIP3_MSA[z3];
    const metro = msaCode ? METRO_WAGES.find((m) => m.id === msaCode) : undefined;

    return { state, metroId: msaCode, metro };
}
